// Logo component with embedded base64 images — no file imports needed
const LOGO_WHITE = 'data:image/png;base64,'
const LOGO_GREEN = 'data:image/png;base64,'

export function LogoWhite({ style }) {
  return (
    <img
      src={LOGO_WHITE}
      alt="Brouwgilde Breda"
      style={{ display: 'block', ...style }}
    />
  )
}

export function LogoGreen({ style }) {
  return (
    <img
      src={LOGO_GREEN}
      alt="Brouwgilde Breda"
      style={{ display: 'block', ...style }}
    />
  )
}
